class LUPrefix {
    int n;
    int lastUploaded;
    boolean[] uploaded;

    public LUPrefix(int n) {
        this.n = n;
        this.lastUploaded = 0;
        this.uploaded = new boolean[n + 1];
    }

    public void upload(int video) {
        if (video >= lastUploaded && !uploaded[video]) {
            lastUploaded = video;
            while (lastUploaded <= n && uploaded[lastUploaded]) {
                lastUploaded++;
            }
        }
        uploaded[video] = true;
    }

    public int longest() {
        return lastUploaded - 1;
    }
}
```

